import{_ as o,o as a,c as d,a2 as c}from"./chunks/framework.BKG_UbFK.js";const m=JSON.parse('{"title":"Arquitetura","description":"","frontmatter":{},"headers":[],"relativePath":"pt/guide/architecture.md","filePath":"pt/guide/architecture.md"}'),t={name:"pt/guide/architecture.md"};function r(s,e,i,l,n,u){return a(),d("div",null,[...e[0]||(e[0]=[c('<h1 id="arquitetura" tabindex="-1">Arquitetura <a class="header-anchor" href="#arquitetura" aria-label="Permalink to &quot;Arquitetura&quot;">​</a></h1><h2 id="como-funciona-a-resolucao" tabindex="-1">Como funciona a resolução <a class="header-anchor" href="#como-funciona-a-resolucao" aria-label="Permalink to &quot;Como funciona a resolução&quot;">​</a></h2><p>O <code>resolveFor()</code> é o núcleo da autorização contextual do Clearance - ver <a href="/clearance-docs/pt/features/contextual-authorization.html">Autorização Contextual</a> para a API completa. Combina três fontes, por esta ordem de precedência:</p><ol><li><strong>Concessões de papel contextuais</strong> - permissões de papéis que o utilizador detém especificamente dentro deste contexto (<code>clr_role_ctx</code>).</li><li><strong>Concessões de papel globais</strong> - permissões dos papéis do Spatie atribuídos globalmente ao utilizador (para que <code>super_admin</code> e outros papéis globais satisfaçam <code>canIn()</code> para qualquer contexto).</li><li><strong>Substituições por contexto</strong> (<code>clr_ctx_overrides</code>) - <code>forced_on</code> acrescenta uma permissão às anteriores; <code>forced_off</code> remove-a, mesmo que a permissão tenha sido concedida por um papel global. Uma negação ganha sempre.</li></ol><div class="warning custom-block"><p class="custom-block-title">Uma negação ganha sempre</p><p><code>forced_off</code> sobrepõe-se a qualquer permissão concedida por um papel global ou por uma concessão de papel contextual. Não há forma de &quot;superar em prioridade&quot; uma substituição <code>forced_off</code> para o mesmo utilizador/permissão/contexto, a não ser removendo-a.</p></div><h2 id="base-de-dados" tabindex="-1">Base de dados <a class="header-anchor" href="#base-de-dados" aria-label="Permalink to &quot;Base de dados&quot;">​</a></h2><p>O Clearance possui 6 tabelas e nunca altera as tabelas núcleo do Spatie (<code>roles</code>, <code>permissions</code>, <code>model_has_roles</code>, <code>model_has_permissions</code>, <code>role_has_permissions</code>). Todas as FKs que referenciam <code>roles.id</code>/<code>permissions.id</code> fazem cascade ao eliminar, salvo indicação contrária; as tabelas do Spatie não têm FKs a apontar de volta para <code>clr_*</code>.</p><table tabindex="0"><thead><tr><th>Tabela</th><th>Colunas-chave</th></tr></thead><tbody><tr><td><code>clr_meta</code></td><td><code>subject_type</code>, <code>subject_key</code> (únicos em conjunto) - <code>display_name</code>, <code>description</code>, <code>icon_svg</code>, <code>color</code> - metadados de exibição para um papel ou guard</td></tr><tr><td><code>clr_role_meta</code></td><td><code>role_id</code> (único, FK -&gt; <code>roles</code>) - <code>is_locked</code>, <code>scope</code> (<code>global</code>|<code>contextual</code>), <code>context_types</code> (json) - <code>parent_role_id</code> (FK anulável -&gt; <code>roles</code>, <code>ON DELETE SET NULL</code>) - papel-teto</td></tr><tr><td><code>clr_guards</code></td><td><code>name</code> (único), <code>driver</code>, <code>provider</code> - guards geridos através do painel</td></tr><tr><td><code>clr_settings</code></td><td><code>key</code> (único), <code>value</code> - armazenamento de chave/valor em tempo de execução (papel padrão, etc.)</td></tr><tr><td><code>clr_role_ctx</code></td><td><code>user_id</code>, <code>role_id</code> (FK -&gt; <code>roles</code>), <code>context_type</code>, <code>context_id</code> - atribuições de papel contextuais, únicas por <code>(user, role, context_type, context_id)</code></td></tr><tr><td><code>clr_ctx_overrides</code></td><td><code>user_id</code>, <code>role_id</code> (FK -&gt; <code>roles</code>), <code>permission_id</code> (FK -&gt; <code>permissions</code>), <code>context_type</code>, <code>context_id</code>, <code>type</code> (<code>forced_on</code>|<code>forced_off</code>) - substituições de permissão por utilizador, por contexto</td></tr></tbody></table><h2 id="nunca-toca-nas-tabelas-do-spatie" tabindex="-1">Nunca toca nas tabelas do Spatie <a class="header-anchor" href="#nunca-toca-nas-tabelas-do-spatie" aria-label="Permalink to &quot;Nunca toca nas tabelas do Spatie&quot;">​</a></h2><p>O Clearance foi concebido para coexistir com o <code>spatie/laravel-permission</code>, não para o substituir. Todo o registo <code>Role</code> e <code>Permission</code> que um painel Clearance cria ou edita é um modelo Spatie genuíno, guardado nas próprias tabelas do Spatie. O Clearance nunca executa uma migração que acrescente uma coluna a, ou escreva uma FK a partir de, qualquer uma das tabelas <code>roles</code>, <code>permissions</code>, <code>model_has_roles</code>, <code>model_has_permissions</code>, ou <code>role_has_permissions</code>.</p><p>Todos os dados próprios do Clearance - metadados de exibição, escopo e tetos de papel, atribuições contextuais, substituições por contexto, definições de guard, e configurações - residem exclusivamente nas 6 tabelas <code>clr_*</code> acima. Isto significa que:</p><ul><li>Desinstalar o Clearance nunca arrisca corromper os seus dados existentes de papéis/permissões do Spatie.</li><li>Qualquer código que já leia diretamente os modelos ou tabelas do Spatie continua a funcionar sem modificações.</li><li>As funcionalidades contextuais e de teto do Clearance são camadas puramente aditivas, resolvidas em tempo de consulta (via <code>resolveFor()</code> e <code>RoleService</code>), e não incorporadas no esquema do Spatie.</li></ul><h2 id="relacionado" tabindex="-1">Relacionado <a class="header-anchor" href="#relacionado" aria-label="Permalink to &quot;Relacionado&quot;">​</a></h2><ul><li><a href="/clearance-docs/pt/features/contextual-authorization.html">Autorização Contextual</a> - <code>canIn()</code>, <code>hasRoleIn()</code>, diretivas Blade, <code>ContextService</code></li><li><a href="/clearance-docs/pt/features/roles.html">Papéis</a> - escopo e papéis-teto, <code>RoleService::setParent()</code></li><li><a href="/clearance-docs/pt/guide/migration.html">Migração</a> - fazer o backfill de <code>clr_meta</code>/<code>clr_role_meta</code>/<code>clr_guards</code> numa instalação Spatie existente</li><li><a href="/clearance-docs/pt/guide/security.html">Segurança</a> - como o modelo de teto e substituição previne o escalonamento de privilégios</li></ul>',14)])])}const _=o(t,[["render",r]]);export{m as __pageData,_ as default};
